import{_ as t,c as s,o as a,ae as n}from"./chunks/framework.B7Y1jjX-.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"generated-notes/前端/三件套/CSS层叠样式表/css/层叠上下文.md","filePath":"generated-notes/前端/三件套/CSS层叠样式表/css/层叠上下文.md"}'),r={name:"generated-notes/前端/三件套/CSS层叠样式表/css/层叠上下文.md"};function o(_,e,i,d,p,c){return a(),s("div",null,[...e[0]||(e[0]=[n('<p>HTML 元素沿着其相对于用户的一条虚构的 z 轴排开，<strong>层叠上下文</strong>就是对这些 HTML 元素的一个三维构想。众 HTML 元素基于其元素属性按照优先级顺序占据这个空间。</p><p>==子级层叠上下文的 <code>z-index</code> 值只在父级中才有意义==。子级层叠上下文被自动视为父级层叠上下文的一个独立单元。 <a href="/pressidian/pressidian/notes/attachments/Pasted%20image%2020250903165945.png">查看图片：Pasted image 20250903165945.png</a></p><p>总结：</p><ul><li>层叠上下文可以包含在其他层叠上下文中，并且一起创建一个层叠上下文的层级。</li><li>每个层叠上下文都完全独立于它的兄弟元素：当处理层叠时只考虑子元素。</li><li>每个层叠上下文都是自包含的：当一个元素的内容发生层叠后，该元素将被作为整体在父级层叠上下文中按顺序进行层叠。</li></ul>',4)])])}const S=t(r,[["render",o]]);export{m as __pageData,S as default};
